import React, { useState } from "react";
import { usePlans } from "../lib/usePlans";
import { useAuth } from "../lib/auth";
import { initiatePurchase } from "../lib/purchase";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";
import PlanCard from "../components/PlanCard";
import Footer from "../components/Footer";

export default function Plans() {
  const plans = usePlans(true);
  const [loadingId, setLoadingId] = useState(null);
  const { user } = useAuth();
  const navigate = useNavigate();

  const buy = async (id) => {
    if (!user) { navigate("/signup"); return; }
    setLoadingId(id);
    try {
      await initiatePurchase(id);
    } catch (e) {
      toast.error(e?.response?.data?.detail || "Purchase failed.");
    } finally {
      setLoadingId(null);
    }
  };

  return (
    <>
      <main className="max-w-7xl mx-auto px-6 py-14">
        <div className="tag-uppercase text-volt mb-2">Pricing</div>
        <h1 className="font-heading font-black text-4xl sm:text-5xl tracking-tighter mb-3">Four plans. Four private WhatsApp groups.</h1>
        <p className="text-white/60 max-w-2xl mb-10">
          Every dollar you pay becomes 1 credit. Each day of premium access consumes 1 credit — so you always know exactly what you&apos;re getting.
          Payments are processed on our secure external gateway; your membership activates the moment our team approves it.
        </p>

        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
          {plans.map((p) => (
            <PlanCard key={p.id} plan={p} loading={loadingId === p.id} onBuy={buy} testId={`plans-page-card-${p.id}`} />
          ))}
        </div>
      </main>
      <Footer />
    </>
  );
}
